#!/usr/bin/env bash
# rumbod-cli — self-contained base64 install
# Just paste this entire file into your terminal.
set -euo pipefail

echo ""
echo "  ╭─────────────────────────────────────╮"
echo "  │        rumbod-cli installer         │"
echo "  ╰─────────────────────────────────────╯"
echo ""

# Decode embedded tarball
PAYLOAD_LINE=$(grep -n '^__PAYLOAD__' "$0" | cut -d: -f1)
tail -n +$((PAYLOAD_LINE + 1)) "$0" | base64 -d > /tmp/rum.tar.gz 2>/dev/null || {
    echo "✗ Failed to decode payload. Need base64 command."
    exit 1
}

TMPDIR="$(mktemp -d)"
cd "$TMPDIR"
tar xzf /tmp/rum.tar.gz
cd rumbod-cli-*

# Ensure uv
if ! command -v uv &>/dev/null; then
    echo "→ Installing uv..."
    curl -LsSf https://astral.sh/uv/install.sh | sh
    export PATH="$HOME/.local/bin:$PATH"
fi

# Install
echo "→ Installing rumbod-cli..."
uv tool install --force . 2>/dev/null || pip install . --break-system-packages 2>/dev/null || {
    pip install dist/*.whl --break-system-packages
}

# ~/.rum/ 
mkdir -p ~/.rum/{skills,agent-monitor,ponytail,hooks,steering,logs,sessions}
touch ~/.rum/knowledge-base.md 2>/dev/null || true

# API key wizard
if [ -z "${RUMBOD_NVIDIA_API_KEY:-}" ] && [ -z "${RUMBOD_OPENAI_API_KEY:-}" ] && [ -z "${RUMBOD_ANTHROPIC_API_KEY:-}" ]; then
    echo ""
    echo "→ API Key Setup (press Enter to skip)"
    echo ""
    read -rp "  NVIDIA NIM API Key: " nk
    [ -n "$nk" ] && echo "export RUMBOD_NVIDIA_API_KEY='$nk'" >> ~/.bashrc && export RUMBOD_NVIDIA_API_KEY="$nk"
    read -rp "  OpenAI API Key: " ok
    [ -n "$ok" ] && echo "export RUMBOD_OPENAI_API_KEY='$ok'" >> ~/.bashrc && export RUMBOD_OPENAI_API_KEY="$ok"
    read -rp "  Anthropic API Key: " ak
    [ -n "$ak" ] && echo "export RUMBOD_ANTHROPIC_API_KEY='$ak'" >> ~/.bashrc && export RUMBOD_ANTHROPIC_API_KEY="$ak"
fi

rm -rf /tmp/rum.tar.gz "$TMPDIR"

echo ""
echo "  ╭─────────────────────────────────────╮"
echo "  │  Done!                              │"
echo "  │                                     │"
echo "  │  rum-interactive-cli                │"
echo "  │  rum-cli chat 'hello'               │"
echo "  ╰─────────────────────────────────────╯"

exit 0
